package com.jdmedia.service;
import com.jdmedia.model.*;import javafx.concurrent.Task;import java.io.*;import java.nio.file.*;import java.time.*;import java.util.*;
public final class ConversionService {private final SettingsService settings;private final HistoryService history;private volatile ConversionSummary lastSummary;private Boolean nvencAvailable;private volatile Path lastOutputDirectory;private volatile Path lastOutputFile;private record ProcessResult(int code,String diagnostic){}public ConversionService(SettingsService settings,HistoryService history){this.settings=settings;this.history=history;}public ConversionSummary lastSummary(){return lastSummary;}public Path lastOutputDirectory(){return lastOutputDirectory;}public Path lastOutputFile(){return lastOutputFile;}public synchronized boolean supportsNvenc(){if(nvencAvailable!=null)return nvencAvailable;try{Process p=new ProcessBuilder(settings.get().ffmpegPath,"-hide_banner","-f","lavfi","-i","color=c=black:s=320x240:d=0.1","-c:v","h264_nvenc","-f","null","-").redirectErrorStream(true).start();p.getInputStream().readAllBytes();nvencAvailable=p.waitFor()==0;}catch(Exception ignored){nvencAvailable=false;}return nvencAvailable;}
public Task<Void> createTask(List<MediaFile> media,ConversionOptions options,Path output){return new Task<>(){protected Void call()throws Exception{Files.createDirectories(output);lastOutputDirectory=output;lastOutputFile=null;Instant batch=Instant.now();int done=0,ok=0;long original=0,finalSize=0;boolean nvenc=supportsNvenc();for(MediaFile file:media){if(isCancelled())break;Instant start=Instant.now();Path target=output.resolve(stripExtension(file.fileName())+"_JDPM.mp4");if(file.path().toAbsolutePath().normalize().equals(target.toAbsolutePath().normalize()))throw new IOException("La carpeta de salida no puede sobrescribir el archivo original: "+file.fileName());updateMessage("Convirtiendo"+(nvenc?" con NVIDIA: ":": ")+file.fileName());ProcessResult result=run(file,target,options,nvenc,done,media.size());if(isCancelled())break;long size=Files.exists(target)?Files.size(target):0;boolean success=result.code()==0&&size>0;history.add(new ConversionRecord(start,file.path().toString(),target.toString(),file.sizeBytes(),size,Duration.between(start,Instant.now()).toSeconds(),(nvenc?"NVENC":"CPU")+" / calidad "+options.crf(),success?"Completada":"Error FFmpeg: "+result.diagnostic()));if(!success)throw new IOException((nvenc?"NVENC":"FFmpeg")+" no pudo convertir "+file.fileName()+": "+result.diagnostic());lastOutputFile=target;ok++;original+=file.sizeBytes();finalSize+=size;if(options.deleteOriginals())Files.delete(file.path());updateProgress(++done,media.size());}lastSummary=new ConversionSummary(media.size(),ok,original,finalSize,Duration.between(batch,Instant.now()).toSeconds(),isCancelled());return null;}private ProcessResult run(MediaFile file,Path target,ConversionOptions options,boolean nvenc,int done,int total)throws Exception{Process p=new ProcessBuilder(command(file,target,options,nvenc)).redirectErrorStream(true).start();StringBuilder errors=new StringBuilder();try(BufferedReader reader=p.inputReader()){String line;while((line=reader.readLine())!=null&&!isCancelled()){if(line.startsWith("out_time_ms=")){try{long microseconds=Long.parseLong(line.substring(12));double fileProgress=file.durationSeconds()==0?0:Math.min(1,microseconds/(file.durationSeconds()*1_000_000d));updateProgress((done+fileProgress)/total,1);}catch(NumberFormatException ignored){}}else if(!line.startsWith("progress=")){errors.append(line).append('\n');if(errors.length()>1800)errors.delete(0,errors.length()-1800);}}}if(isCancelled())p.destroyForcibly();int code=p.waitFor();String text=errors.toString().trim();return new ProcessResult(code,text.isBlank()?"código "+code:text);}};}
private List<String> command(MediaFile file,Path target,ConversionOptions o,boolean nvenc){List<String> c=new ArrayList<>(List.of(settings.get().ffmpegPath,"-y","-progress","pipe:1","-nostats"));if(nvenc)c.addAll(List.of("-hwaccel","cuda","-hwaccel_output_format","cuda"));c.addAll(List.of("-i",file.path().toString(),"-map","0:v:0"));Integer audio=o.audioStreamIndexes().get(file.path());if(audio!=null)c.addAll(List.of("-map","0:"+audio));if(o.subtitles()==ConversionOptions.SubtitleMode.KEEP){List<StreamInfo> compatible=file.subtitleStreams().stream().filter(this::isMp4TextSubtitle).toList();for(StreamInfo subtitle:compatible)c.addAll(List.of("-map","0:"+subtitle.index()));if(!compatible.isEmpty())c.addAll(List.of("-c:s","mov_text"));}if(nvenc)c.addAll(List.of("-vf","scale_cuda=-2:1080:format=nv12","-c:v","h264_nvenc","-preset","p4","-rc","constqp","-qp",String.valueOf(o.crf())));else c.addAll(List.of("-c:v","libx264","-preset",o.preset(),"-crf",String.valueOf(o.crf()),"-vf","scale=-2:1080","-pix_fmt","yuv420p"));c.addAll(List.of("-c:a","aac","-b:a","192k","-ac","2","-movflags","+faststart",target.toString()));return c;}private boolean isMp4TextSubtitle(StreamInfo subtitle){return Set.of("subrip","srt","ass","ssa","webvtt","mov_text").contains(subtitle.codec().toLowerCase());}private String stripExtension(String name){int dot=name.lastIndexOf('.');return dot<0?name:name.substring(0,dot);}}
